import java.util.*; class Employee2{ String dept; int salary; Employee2(String d,int s){dept=d;salary=s;} public String toString(){return dept+":"+salary;} } public class Six{ public static void main(String[] args){ List<Employee2> list=new ArrayList<>(); list.add(new Employee2("IT",5000)); list.add(new Employee2("HR",3000)); list.add(new Employee2("IT",2000)); Collections.sort(list,(a,b)->{ int r=a.dept.compareTo(b.dept); return r!=0?r:a.salary-b.salary;}); System.out.println(list); }}